mapper.select:
SELECT COALESCE(ppr.room_price, rm.base_price)
FROM room_master rm LEFT JOIN pricing_policy_room ppr ON rm.room_no = ppr.room_no
                    LEFT JOIN pricing_policy pp ON ppr.policy_id = pp.policy_id
WHERE rm.room_no = #{roomNo} AND (pp.policy_id IS NULL
      OR (#{checkinDate} BETWEEN pp.start_date
          AND pp.end_date
          AND (pp.repeat_type = 'None'
                   OR (pp.repeat_type = 'Weekly' AND DAYOFWEEK(#{checkinDate}) IN (1, 7))
                   OR (pp.repeat_type = 'Monthly' AND DAYOFMONTH(#{checkinDate}) = pp.repeat_value)
            )
        )
    )
ORDER BY pp.discount_rate DESC LIMIT 1;
